			&lt;p&gt;&lt;u&gt;&lt;strong&gt;96वां संविधान संशोधन अधिनियम&lt;/strong&gt;&lt;/u&gt;&lt;/p&gt;
			&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;&lt;strong&gt;ओरिया भाषा के लिए ओडिया प्रतिस्थापित किया गया&lt;/strong&gt;&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
			&lt;td&gt;&lt;u&gt;&lt;strong&gt;2011&lt;/strong&gt;&lt;/u&gt;&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td&gt;97वां संविधान संशोधन अधिनियम&lt;/td&gt;
			&lt;td&gt;
			&lt;ul&gt;
				&lt;li&gt;सहकारी समिति को संवैधानिक संरक्षण और दर्जा।&lt;/li&gt;
			&lt;/ul&gt;
			&lt;/td&gt;
			&lt;td&gt;2011&lt;/td&gt;
